const scannerList = [];

for (let index = 1; index < 4; index++) {
    scannerList.push({
        idx: index,
        name: `스캐너_${index}`,
        sensorId: `id_${index}`,
        circleInfo: {
            detection: `${index}000`,
            defense: `${index}00`,
            center: `${index}0`,
        },
        locationAuto: index === 3 ? true : false,
    });
}

export default scannerList;
