<template>
    <div>
        <div class="table_wrap">
            <h4>스캐너</h4>
            <div>
                <v-data-table :headers="headers" :items="dataList" no-data-text="데이터가 존재하지 않습니다." hide-default-footer>
                    <template #item="{ item }">
                        <tr @dblclick="selectList(item)" :class="selectInfo.idx === item.idx ? 'active' : ''">
                            <td>{{ item.DEVICE_NAME }}</td>
                            <td>{{ item.SENSOR_ID }}</td>
                            <td>{{ getCircleInfo(item) }}</td>
                            <td>{{ item.COORDINATE_TYPE === 'A' ? 'auto' : 'passive' }}</td>
                        </tr>
                    </template>
                </v-data-table>
            </div>
        </div>
        <p class="txt_note">수정할 정보를 더블 클릭해주세요.</p>
        <ScannerSettingPopup v-if="isPopupOpen" :selectInfo="selectInfo" @popupCloseYes="onUpdate" @popupCloseNo="onUpdateCancel"/>
        <AlertModal :params="alertModalParams"></AlertModal>
    </div>
</template>

<script>
import ScannerSettingPopup from '@/components/popup/setting/ScannerSetting';
import scannerList from '@/data/scannerList';

import * as LogUtil from "@/common/LogUtil";
import * as DeviceConfigScanner from "@/rest/DeviceConfigScanner";

import AlertModal from '@/components/modal/AlertModal'

export default {
    components: {
      ScannerSettingPopup,
      AlertModal
    },
    data: () => ({
      alertModalParams: { isOpened: false, title: '', message: ''},
      dataList: [],
      selectInfo: {},
      isPopupOpen: false,
      headers: [
          { text: '이름', value: 'DEVICE_NAME', sortable: false },
          { text: '센서ID', value: 'SENSOR_ID' },
          { text: '(탐지 원, 방어 원, 중심 원 반지름[m])', value: 'CIRCLE_INFO', sortable: false },
          { text: '스캐너 위치', value: 'COORDINATE_TYPE', sortable: false },
      ],
    }),
    beforeMount() {
        // this.dataList = scannerList;
        this.initDataList();
    },
    methods: {
      showAlertModal(msg) {
        this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
      },
      popupView(view) {
        this.isPopupOpen = view;

        if (!view) {
          this.selectInfo = {};
        }
      },
      onUpdate() {
        LogUtil.debug('DeviceScanner: onUpdate()');
        this.isPopupOpen = false;
        this.initDataList();
      },
      onUpdateCancel() {
        this.isPopupOpen = false;
        LogUtil.debug('DeviceScanner: onUpdateCancel()');
      },
      selectList(select) {
        this.selectInfo = select;
        this.popupView(true);
      },
      initDataList(condition) {
        let options = {
          conditions: [
            // { clause: 'and', name: 'MEMBER_TYPE', operator: '=', value: 'H'},
          ],
          orderBys: [
            { name: 'DEVICE_NAME', operator: 'asc'}
          ],
          paging: { pageNo: 1, pageSize: 100 }
        };
        if(condition != null) options.conditions.push(condition);

        DeviceConfigScanner.listByCondition(options).then(res => {
          if(res.data.RES_CODE>=0) {
            this.dataList = res.data.ITEMS;
            // this.dataList.forEach((item)=>{
            //   if(item.DETECT_RADIUS != null && item.DEFENSE_RADIUS != null && item.CENTER_RADIUS != null ) {
            //     item.CIRCLE_INFO = '(' + item.DETECT_RADIUS + ',' + item.DEFENSE_RADIUS + ',' + item.CENTER_RADIUS + ')';
            //   }
            // });
            LogUtil.debug("this.dataList=", this.dataList);
          } else {
            this.showAlertModal(res.data.RES_MSG);
          }
        }).catch(e => {
          LogUtil.error("error=", e);
          this.showAlertModal(e);
        }).finally(() => {
        });
      },
      getCircleInfo(item) {
        if(item.DETECT_RADIUS != null && item.DEFENSE_RADIUS != null && item.CENTER_RADIUS != null ) {
          return '(' + item.DETECT_RADIUS + ',' + item.DEFENSE_RADIUS + ',' + item.CENTER_RADIUS + ')';
        } else {
          return null;
        }
      }
    },
};
</script>

<style lang="scss" scoped>
.table_wrap {
    width: 800px;
    border: 1px solid $color-main03;
    border-radius: 10px;
    margin: 60px auto 0;
    & > div {
        padding: 31px 50px 48px;
    }
    h4 {
        @include centerAlign();
        height: 60px;
        border-bottom: 1px solid $color-main03;
        font: {
            size: 20px;
            weight: 600;
        }
    }
}
.txt_note {
    width: 800px;
    margin: 21px auto 0;
    padding-left: 50px;
    background: url('@/assets/setting/ico_note.svg') no-repeat 16px center;
    font: {
        size: 18px;
        weight: 600;
    }
    color: #ae0003;
}
</style>
