<template>
    <div class="popup_wrap">
        <div class="popup_content">
            <p class="popup_title">{{ selectInfo.DEVICE_NAME }} 설정</p>
            <dl>
                <dt>센서 ID :</dt>
                <dd><input type="text" v-model="model.SENSOR_ID" /></dd>
            </dl>
            <dl>
                <dt>탐지 원 반지름[m] :</dt>
                <dd><input type="number" v-model="model.DETECT_RADIUS" max="5000" min="500" /></dd>
            </dl>
            <dl>
                <dt>방어 원 반지름[m] :</dt>
                <dd><input type="number" v-model="model.DEFENSE_RADIUS" max="5000" min="500" /></dd>
            </dl>
            <dl>
                <dt>중심 원 반지름[m] :</dt>
                <dd><input type="number" v-model="model.CENTER_RADIUS" max="5000" min="500" /></dd>
            </dl>
            <dl>
                <dt>스캐너 위치 :</dt>
                <dd>
                    <v-radio-group hide-details v-model="model.COORDINATE_TYPE" row>
                        <v-radio v-for="n in ['A','M']" :key="n" :label="n === 'A' ? '자동' : '수동'" :value="n"></v-radio>
                    </v-radio-group>
                </dd>
            </dl>
            <dl>
                <dt :class="model.COORDINATE_TYPE === 'M' ? 'disable' : ''">위도 :</dt>
                <dd>
                    <input type="text" v-model="model.LATITUDE" :disabled="model.COORDINATE_TYPE === 'A'" />
                </dd>
                <dt :class="model.COORDINATE_TYPE === 'M' ? 'disable' : ''">경도 :</dt>
                <dd>
                    <input type="text" v-model="model.LONGITUDE" :disabled="model.COORDINATE_TYPE === 'A'" />
                </dd>
            </dl>
            <div class="btn_area">
                <v-btn elevation="3" color="primary" @click="doSave"> 확인 </v-btn>
                <v-btn outlined plain elevation="3" @click="popupCloseNo">취소</v-btn>
            </div>
        </div>
        <AlertModal :params="alertModalParams"></AlertModal>
    </div>
</template>
<script>
import * as LogUtil from "@/common/LogUtil";

import * as DeviceConfigScanner from "@/rest/DeviceConfigScanner";
import AlertModal from '@/components/modal/AlertModal'

export default {
  components: {
    AlertModal
  },
  data: () => ({
    alertModalParams: { isOpened: false, title: '', message: ''},
    model: {}
  }),
  props: ['selectInfo'],
  mounted() {
    this.model = this.selectInfo;
    this.model.COORDINATE_TYPE = this.model.COORDINATE_TYPE === null ? 'A' : this.model.COORDINATE_TYPE;
    LogUtil.debug('ScannerSetting: mounted(): this.selectInfo=', this.selectInfo);
    LogUtil.debug('ScannerSetting: mounted(): this.model=', this.model);
  },
  methods: {
    showAlertModal(msg) {
      this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
    },
    popupCloseNo() {
      this.$emit('popupCloseNo', false);
      LogUtil.debug('ScannerSetting: popupCloseNo()');
    },
    doSave() {
      LogUtil.debug('ScannerSetting: doSave(): this.model=', this.model);
      let model = {
        DEVICE_CONFIG_SCANNER_ID: this.model.DEVICE_CONFIG_SCANNER_ID != null ? this.model.DEVICE_CONFIG_SCANNER_ID : -1,
        DEVICE_ID: this.model.DEVICE_ID,
        SENSOR_ID: this.model.SENSOR_ID,
        DETECT_RADIUS: this.model.DETECT_RADIUS,
        DEFENSE_RADIUS: this.model.DEFENSE_RADIUS,
        CENTER_RADIUS: this.model.CENTER_RADIUS,
        COORDINATE_TYPE: this.model.COORDINATE_TYPE,
        LATITUDE: this.model.LATITUDE,
        LONGITUDE: this.model.LONGITUDE,
      }
      LogUtil.debug('ScannerSetting: doSave(): model=', model);
      DeviceConfigScanner.save(model).then(res => {
        if(res.data.RES_CODE>=0) {
          LogUtil.debug('ScannerSetting: doSave(): res.data.RES_CODE=', res.data);
          if(this.model.DEVICE_CONFIG_SCANNER_ID === -1) {
            this.model.DEVICE_CONFIG_SCANNER_ID = res.data.insertId;
            LogUtil.debug('ScannerSetting: doSave(): this.model=', this.model);
          } else {
            LogUtil.debug('ScannerSetting: doSave(): this.model.DEVICE_CONFIG_SCANNER_ID=', this.model.DEVICE_CONFIG_SCANNER_ID);
          }
          this.$emit('popupCloseYes', false);
        } else {
          this.showAlertModal(res.data.RES_MSG);
        }
      }).catch(e => {
        LogUtil.error("error=", e);
        this.showAlertModal(e);
      }).finally(() => {
      });
    },
  },
};
</script>

<style lang="scss" scoped>
.popup_wrap {
    .popup_content {
        width: 600px;
        padding: 0 10px;
        .popup_title {
            @include centerAlign();
            height: 52px;
            margin-bottom: 27px;
            border-bottom: 1px solid #ccc;
            font: {
                size: 20px;
                weight: 600;
            }
        }
        dl {
            @include hCenterAlign();
            & + dl {
                margin-top: 20px;
            }
            dt {
                width: 170px;
                padding-right: 14px;
                text-align: right;
                font: {
                    size: 15px;
                    weight: 700;
                }
                &.disable {
                    color: #ccc;
                }
            }
            dd {
                input[type='text'],
                input[type='number'] {
                    width: 200px;
                    height: 38px;
                    border: 1px solid #ccc;
                    border-radius: 8px;
                    text-align: center;
                }
                & + dt {
                    width: 80px;
                }
                .v-input--selection-controls {
                    margin-top: 0 !important;
                    padding-top: 0 !important;
                }
            }
        }
        .btn_area {
            @include centerAlign();
            width: 100%;
            margin-top: 45px;
            border-top: 1px solid #ccc;
            button + button {
                margin-left: 14px;
            }
        }
    }
}
</style>
